      function CF_PERSON_NAMEFormula return Char is

 v_Psv_user_id VARCHAR2(15);
 V_PERSON_NAME VARCHAR2(100);

Cursor cur_Psv_user_id is 
SELECT Created_By
FROM PEN_DECISION_INSTANCE
WHERE  PEN_DECISION_INSTANCE.Dec_Incr_Seq_No=:P_Dec_Incr_Sec_No
AND PEN_DECISION_INSTANCE.Dt_Dec_Unit_Code=:P_Dt_Dec_Unit_Code
AND PEN_DECISION_INSTANCE.Dt_Decision_Year=:P_Dt_Decision_Year
AND PEN_DECISION_INSTANCE.Dt_Document_Type_Dec_Code='1';

begin
   --Psv_User_Id    := Sec_Appl_Pkg.Get_Current_User(:P_Login_Id);
   
   	OPEN cur_Psv_user_id;
	  FETCH cur_Psv_user_id
	  INTO v_Psv_user_id;
	  CLOSE cur_Psv_user_id;

   SELECT PERSON_SURNAME || ' ' ||PERSON_NAME
   INTO V_PERSON_NAME
   FROM SEC_USERS  
   WHERE USER_ID = v_Psv_user_id;

   RETURN V_PERSON_NAME; 
end;

