      function CF_13Formula return char is

V_date	DATE;
v_year	NUMBER;
V				varchar2(20);

CURSOR CUR IS
SELECT A.QUAL_DATE
FROM PEN_ACCOUNT_INFO A
WHERE A.ACCOUNT_NO= :P_ACC_ACCOUNT_NO;

CURSOR CUR2 IS
SELECT A.QUAL_YEAR
FROM PEN_ACCOUNT_INFO A
WHERE A.ACCOUNT_NO= :P_ACC_ACCOUNT_NO;

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_date;
  CLOSE CUR;
  
  IF V_date IS NOT NULL THEN
  	V := TO_CHAR(V_date,'DD/MM/RRRR');
  ELSE
  	  OPEN CUR2;
		  FETCH CUR2 
		  INTO v_year;
		  CLOSE CUR2;
		  IF v_year IS NOT NULL THEN
		  	V := TO_CHAR(v_year);
		  END IF;
  END IF;
  
  RETURN V;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

