      function M_64FormatTrigger return boolean is
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;


begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	  
  IF NVL(V_01_01_2019,'0') = '1' OR NVL(V_01_10_2019,'0') = '1' --OR (:CF_35='00008' AND :P_FACTITIOUS_DATE >= TO_DATE('01/01/2019','DD/MM/YYYY'))
  	THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;

  return (TRUE);
end;

      function CF_PLAFONFormula return Number is

V_PLAFON		NUMBER;
CURSOR	CUR_PLAFON IS
SELECT AMOUNT
FROM   PEN_QT_PER_BE_CC_PER_ACCOUNT A,
			 PEN_ACCOUNT B
WHERE  B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND    B.ACCOUNT_NO = A.ACC_ACCOUNT_NO
AND    A.CP_CALCULATION_PARAMETER_CODE = 'PLAFN';
			 
begin

OPEN	CUR_PLAFON;
FETCH	CUR_PLAFON
INTO	V_PLAFON;
CLOSE	CUR_PLAFON;

RETURN (NVL(V_PLAFON,0));


end;

